-- V037 — Obligation-CTE Rule Mapping + event_type constraint update
-- Maps each of 82 FSMA 204 obligations to CTE types and required KDEs
-- Enables automated per-event obligation compliance checking

BEGIN;

-- 1. Create obligation_cte_rules table
CREATE TABLE IF NOT EXISTS obligation_cte_rules (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    obligation_id UUID NOT NULL REFERENCES obligations(id) ON DELETE CASCADE,
    cte_type TEXT NOT NULL,
    required_kde_key TEXT,
    validation_rule TEXT NOT NULL DEFAULT 'present',
    description TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT obligation_cte_rules_cte_type_check CHECK (cte_type IN (
        'harvesting', 'cooling', 'initial_packing', 'first_land_based_receiving',
        'shipping', 'receiving', 'transformation', 'all', 'record_maintenance'
    ))
);

CREATE INDEX IF NOT EXISTS idx_obligation_cte_rules_cte_type ON obligation_cte_rules(cte_type);
CREATE INDEX IF NOT EXISTS idx_obligation_cte_rules_obligation ON obligation_cte_rules(obligation_id);

-- 2. Update event_type constraint to include first_land_based_receiving
ALTER TABLE fsma.cte_events DROP CONSTRAINT IF EXISTS cte_events_event_type_check;
ALTER TABLE fsma.cte_events ADD CONSTRAINT cte_events_event_type_check
CHECK (event_type IN (
    'harvesting', 'cooling', 'initial_packing', 'first_land_based_receiving',
    'shipping', 'receiving', 'transformation'
));

-- 3. Seed obligation-CTE rules (idempotent)
DELETE FROM obligation_cte_rules;


COMMIT;